const Timer = forwardRef((props, ref) => {
  const startTime = useRef(Date.now());

  useImperativeHandle(ref, () => ({
    reset: () => (startTime.current = Date.now()),
    getElapsed: () => Date.now() - startTime.current,
  }));

  return <p>Таймер запущен...</p>;
});

function App() {
  const timerRef = useRef();

  return (
    <div>
      <Timer ref={timerRef} />
      <button onClick={() => console.log(timerRef.current.getElapsed())}>
        Показать прошедшее время
      </button>
      <button onClick={() => timerRef.current.reset()}>Сбросить</button>
    </div>
