function Box() {
  const boxRef = useRef(null);
  const [width, setWidth] = useState(0);

  useLayoutEffect(() => {
    // Выполняется до отрисовки браузера
    const rect = boxRef.current.getBoundingClientRect();
    setWidth(rect.width);
  }, []);

  return (
    <div ref={boxRef} style={{ width: "50%" }}>
      Ширина блока: {width}px
    </div>
