:"useCallback"},{"type":"text","text":" для стабильности ссылок."}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Никакого JSX и DOM-манипуляций."}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Не тянуть CSS/UI-концерны (классы, aria-атрибуты) — максимум подготовить данные для них (например, "},{"type":"text","marks":[{"type":"code"}],"text":"isOpen"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"getItemProps()"},{"type":"text","text":" и т.п.)."}]}]}]},{"type":"heading","attrs":{"textAlign":null,"level":1},"content":[{"type":"text","text":"Мини-чеклист для компонента (UI)"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Никакой бизнес-логики/загрузки/валидации внутри — только рендер."}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Получает из хука всё готовое."}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Легко переиспользуется и переоформляется."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Паттерн 1: “Headless hook” + любой UI"}]},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"Хук (логика списка задач)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// useTodos.ts
import { useEffect, useMemo, useReducer, useCallback } from "react";

type Todo = { id: string; title: string; done: boolean };
type State = { items: Todo[]; filter: "all"|"done"|"todo" };
type Action =
  | { type: "load"; payload: Todo[] }
  | { type: "add"; title: string }
  | { type: "toggle"; id: string }
  | { type: "setFilter"; filter: State["filter"] };

function reducer(state: State, action: Action): State {
  switch (action.type) {
    case "load": return { ...state, items: action.payload };
    case "add":  return { ...state, items: [...state.items, { id: crypto.randomUUID(), title: action.title, done: false }] };
    case "toggle": return { ...state, items: state.items.map(t => t.id === action.id ? { ...t, done: !t.done } : t) };
    case "setFilter": return { ...state, filter: action.filter };
    default: return state;
  }
}

export function useTodos() {
  const [state, dispatch] = useReducer(reducer, { items: [], filter: "all" });

  useEffect(() => {
    // бизнес-логика загрузки (можно заменить fetch’ем)
    const saved = localStorage.getItem("todos");
    if (saved) dispatch({ type: "load", payload: JSON.parse(saved) });
  }, []);

  useEffect(() => {
    localStorage.setItem("todos", JSON.stringify(state.items));
  }, [state.items]);

  const visible = useMemo(() => {
    switch (state.filter) {
      case "done": return state.items.filter(t => t.done);
      case "todo": return state.items.filter(t => !t.done);
      default:     return state.items;
    }
  }, [state.items, state.filter]);

  const add    = useCallback((title: string) => dispatch({ type: "add", title }), []);
  const toggle = useCallback((id: string) => dispatch({ type: "toggle", id }), []);
  const setFilter = useCallback((filter: State["filter"]) => dispatch({ type: "setFilter", filter }), []);

  return {
    state,                 // «сырой» стейт, если нужен
    todos: visible,        // производные данные для UI
    actions: { add, toggle, setFilter } // стабилизированные действия
  };
}
"}]},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"Любой UI-компонент на базе хука"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// TodosView.tsx
import { useTodos } from "./useTodos";

export function TodosView() {
  const { todos, state, actions } = useTodos();

  return (
    <div>
      <div>
        <button onClick={() => actions.setFilter("all")}  aria-pressed={state.filter==="all"}>Все</button>
        <button onClick={() => actions.setFilter("todo")} aria-pressed={state.filter==="todo"}>Активные</button>
        <button onClick={() => actions.setFilter("done")} aria-pressed={state.filter==="done"}>Готовые</button>
      </div>

      <form onSubmit={(e) => {
        e.preventDefault();
        const input = (e.currentTarget.elements.namedItem("title") as HTMLInputElement);
        if (input.value.trim()) actions.add(input.value.trim());
        input.value = "";
      }}>
        <input name="title" placeholder="Новая задача" />
        <button type="submit">Добавить</button>
      </form>

      <ul>
        {todos.map(t => (
          <li key={t.id}>
            <label>
              <input type="checkbox" checked={t.done} onChange={() => actions.toggle(t.id)} />
              {t.title}
            </label>
          </li>
        ))}
      </ul>
    </div>
  );
}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"Что вышло:"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"useTodos"},{"type":"text","text":" полностью “headless”: загрузка/сохранение, фильтры, экшены, мемоизации."}]}]},{"type":"listItem","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","marks":[{"type":"code"}],"text":"TodosView"},{"type":"text","text":" — чистый UI: кнопки, список, формы."},{"type":"hardBreak"},{"type":"text","text":"Хочешь другой дизайн (Tailwind, MUI, shadcn) — меняешь только "},{"type":"text","marks":[{"type":"code"}],"text":"TodosView"},{"type":"text","text":"."}]}]}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"Паттерн 2: “Controller/View” (как в Headless UI)"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Хук может возвращать "},{"type":"text","marks":[{"type":"bold"}],"text":"props-геттеры"},{"type":"text","text":", чтобы UI легко связывался с логикой."}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"// useDisclosure.ts
export function useDisclosure(initial = false) {
  const [open, setOpen] = useState(initial);
  const openIt = useCallback(() => setOpen(true), []);
  const close  = useCallback(() => setOpen(false), []);
  const toggle = useCallback(() => setOpen(o => !o), []);

  const getButtonProps = () => ({
    "aria-expanded": open,
    onClick: toggle
  });

  const getPanelProps = () => ({
    role: "region",
    hidden: !open
  });

  return { open, openIt, close, toggle, getButtonProps, getPanelProps };
}
